  font-weight: 600;
  margin-bottom: 10px;
}

.text-blue { color: #2563eb; }
.text-purple { color: #7c3aed; }

/* STEP CARDS */
.step-card {
  padding: 12px;
  border-radius: 10px;
  border: 1px solid;
  margin-bottom: 10px;
}

.step-blue { background:#eff6ff; border-color:#93c5fd; }
.step-purple { background:#f5f3ff; border-color:#c4b5fd; }
.step-green { background:#ecfdf5; border-color:#86efac; }

.step-badge {
  font-size: 11px;
  background: #2563eb;
  color: white;
  padding: 2px 6px;
  border-radius: 6px;
}

.step-title { font-weight: 600; }
.step-sub { font-size: 12px; color: #6b7280; }
.step-value { font-size: 18px; font-weight: bold; }

/* PAYOUT */
.payout-box {
  background: #f5f3ff;
  border: 2px solid #c4b5fd;
  border-radius: 10px;
  padding: 12px;
  margin-bottom: 10px;
}

.payout-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.payout-badge {
  background: #7c3aed;
  color: white;
  padding: 2px 6px;
  border-radius: 6px;
  font-size: 11px;
}

.formula-row {
  display: flex;
  align-items: center;
  gap: 8px;
  margin: 8px 0;
}

.formula-chip {
  background: white;
  padding: 3px 8px;
  border-radius: 6px;
}

.formula-operator {
  color: #7c3aed;
  font-weight: bold;
}

.payout-value {
  text-align: right;
  font-weight: bold;
  color: #16a34a;
}

/* TOTAL */
.example-total-box {
  background: linear-gradient(to right, #ecfdf5, #d1fae5);
  border: 2px solid #86efac;
  border-radius: 10px;
  padding: 15px;
  display: flex;
  justify-content: space-between;
}

.total-label {
  font-size: 12px;
  color: #6b7280;
}

.total-value {
  font-size: 26px;
  font-weight: bold;
  color: #15803d;
}

sp_widget.script:
(function() {
  /* populate the 'data' object */
  /* e.g., data.table = $sp.getValue('table'); */
data.title = 'Incentive Plans';
  data.subtitle = 'Two-phase commission calculation architecture';
  data.activeTab = 'overview';
	data.tableWidget=$sp.getWidget('incentnow-table-widget',{ table: 'x_ctans_incentnow_plan',view:'portal_view',viewperiod:'false'});
  data.isIncentNowGroupAdmin=gs.hasRole('x_ctans_incentnow.business_group_admin') || gs.hasRole('x_ctans_incentnow.admin');


	if(input && input.action=="openassign")
		{
			data.planid=input.planId;
			data.assignuserwidget= $sp.getWidget("incentnow-assignment-user",{table:'x_ctans_incentnow_plan',sysid:input.planId});

		}


	var planGR = new GlideAggregate('x_ctans_incentnow_plan');
	planGR.addAggregate('COUNT');
	planGR.query();

	var totalPlans = 0;

	if (planGR.next()) {
			totalPlans = parseInt(planGR.getAggregate('COUNT'), 10);
	}

	data.stats = {
			totalPlans: totalPlans,
			activePlans: 0,
			assignedReps: 0,
			avgPerPlan: 0
	};




  // Get active plans count
  var activePlanGR = new GlideAggregate('x_ctans_incentnow_plan');
	activePlanGR.addQuery('status', 'active');
	activePlanGR.addAggregate('COUNT');
	activePlanGR.query();

	if (activePlanGR.next()) {
			data.stats.activePlans = parseInt(activePlanGR.getAggregate('COUNT'), 10);
	}

	var ga = new GlideAggregate('x_ctans_incentnow_plan_users');
	ga.addEncodedQuery('x_ctans_incentnow_plan.status!=inactive');
	ga.addAggregate('COUNT', 'x_ctans_incentnow_sales_user');
	ga.groupBy('x_ctans_incentnow_sales_user');
	ga.query();


	data.stats.assignedReps = ga.getRowCount();
	//gs.addInfoMessage(data.stats.avgPerPlan+" -- "+data.stats.activePlans + "   "+data.stats.assignedReps + " -- "+(data.stats.activePlans!=0 && data.stats.assignedReps!=0))

	if(data.stats.activePlans!=0 && data.stats.assignedReps!=0)
	data.stats.avgPerPlan=parseInt(data.stats.activePlans/data.stats.assignedReps);

  // Get all plans for table
  data.plans = [];
  var allPlansGR = new GlideRecordSecure('x_ctans_incentnow_plan');
  allPlansGR.orderByDesc('sys_created_on');
  allPlansGR.setLimit(20);
  allPlansGR.query();

  while (allPlansGR.next()) {
    data.plans.push({
      sys_id: allPlansGR.getUniqueValue(),
      name: allPlansGR.getValue('u_name'),
      type: allPlansGR.getValue('u_plan_type'),
      baseRate: '5%', // Calculate based on plan type
      status: allPlansGR.getValue('u_status'),
      assignedReps: 8 // Count from assignment table
    });
  }

  // Data Gathering Rule Types
  data.dataGatheringRules = [
    {
      type: 'quota_attainment',
      title: 'Quota Attainment',
      icon: 'fa-line-chart',
      bgColor: '#e3f2fd',
      iconColor: '#2196f3',
      description: 'Calculate quota achievement percentage',
      input: 'Earning Rule (Sales)',
      output: 'Quota Attainment %',
      example: '105%',
      formula: 'Sales ÷ Assigned Quota × 100'
    },
    {
      type: 'lookup_rate',
      title: 'Lookup - Commission Rate',
      icon: 'fa-percent',
      bgColor: '#f3e5f5',
      iconColor: '#9c27b0',
      description: 'Retrieve commission rate from lookup table',
      input: 'User Information',
      output: 'Commission Rate %',
      example: '5%',
      formula: 'Match User ID/Role/Team → Return Rate'
    },
    {
      type: 'lookup_variable',
      title: 'Lookup - Variable Pay',
      icon: 'fa-dollar',
      bgColor: '#e8f5e9',
      iconColor: '#4caf50',
      description: 'Retrieve variable pay amount from lookup table',
      input: 'User Information',
      output: 'Variable Pay Amount',
      example: '$25,000',
      formula: 'Match User ID/Role/Team → Return Amount'
    },
    {
      type: 'lookup_bonus',
      title: 'Lookup - Bonus Amount',
      icon: 'fa-gift',
      bgColor: '#fce4ec',
      iconColor: '#e91e63',
      description: 'Retrieve bonus from criteria-based lookup',
      input: 'Bonus Criteria',
      output: 'Bonus Amount',
      example: '$3,000',
      formula: 'Match Product/Deal Type → Return Bonus'
    },
    {
      type: 'range_lookup_highest_tier',
      title: 'Range Lookup - Highest Tier',
      icon: 'fa-arrow-up',
      bgColor: '#fff3e0',
      iconColor: '#ff9800',
      description: 'Get highest achieved tier rate',
      input: 'Quota Attainment %',
      output: 'Highest Tier Rate %',
      example: '7%',
      formula: 'Find Tier Range → Return Highest Rate'
    },
    {
      type: 'range_lookup_progressive_tier',
      title: 'Range Lookup - Progressive Tier',
      icon: 'fa-layer-group',
      bgColor: '#e8eaf6',
      iconColor: '#3f51b5',
      description: 'Get progressive tier rates',
      input: 'Quota Attainment %',
      output: 'Progressive Rate %',
      example: '6.5%',
      formula: 'Calculate Blended Rate Across Tiers'
    }
  ];

  // Payout Examples
  data.payoutExamples = [
    {
      label: 'Example 1',
      title: 'Standard Commission',
      input1: 'ARR Sum',
      input2: 'Commission Rate (5%)',
      calculation: '$100,000 × 5% = $5,000',
      result: '$5,000'
    },
    {
      label: 'Example 2',
      title: 'Variable Pay (OTE)',
      input1: 'Quota Attainment (105%)',
      input2: 'Variable Pay ($25K)',
      calculation: '1.05 × $25,000 = $26,250',
      result: '$26,250'
    },
    {
      label: 'Example 3',
      title: 'Accelerator Commission',
      input1: 'ARR Sum',
      input2: 'Highest Tier Rate (7%)',
      calculation: '$100,000 × 7% = $7,000',
      result: '$7,000'
    },
    {
      label: 'Example 4',
      title: 'Deal Bonus',
      input1: 'Deal Count',
      input2: 'Bonus Amount ($2K)',
      calculation: '3 deals × $2,000 = $6,000',
      result: '$6,000'
    }
  ];

})();
